const { chromium, devices } = require('playwright');
const fs = require('fs');
const path = require('path');

const SCREENSHOT_DIR = '/tmp/ivx-qa-screenshots';
fs.mkdirSync(SCREENSHOT_DIR, { recursive: true });

const RESULTS = {
  report: 'IVX Landing Page QA — End-to-End',
  timestamp: new Date().toISOString(),
  url: 'https://ivxholding.com',
  viewports: {},
  summary: {}
};

async function runViewportTest(browser, viewportName, width, height, deviceScaleFactor) {
  const context = await browser.newContext({
    viewport: { width, height },
    deviceScaleFactor: deviceScaleFactor || 1
  });
  const page = await context.newPage();

  const consoleErrors = [];
  const consoleWarnings = [];
  const networkFailures = [];
  const requests = [];

  page.on('console', msg => {
    if (msg.type() === 'error') consoleErrors.push(msg.text());
    if (msg.type() === 'warning') consoleWarnings.push(msg.text());
  });

  page.on('requestfailed', req => {
    networkFailures.push({ url: req.url(), failure: req.failure()?.errorText });
  });

  page.on('response', resp => {
    requests.push({ url: resp.url(), status: resp.status() });
  });

  try {
    const response = await page.goto('https://ivxholding.com/', { waitUntil: 'networkidle', timeout: 45000 });
    const loadTime = await page.evaluate(() => performance.timing.loadEventEnd - performance.timing.navigationStart);

    // Full page screenshot
    await page.screenshot({ path: path.join(SCREENSHOT_DIR, `${viewportName}-fullpage.png`), fullPage: true });

    // Above-the-fold screenshot
    await page.screenshot({ path: path.join(SCREENSHOT_DIR, `${viewportName}-viewport.png`), fullPage: false });

    // Section-by-section analysis
    const sections = await page.evaluate(() => {
      const els = document.querySelectorAll('section');
      return Array.from(els).map(e => {
        const rect = e.getBoundingClientRect();
        const style = window.getComputedStyle(e);
        return {
          id: e.id || '(no-id)',
          className: e.className.substring(0, 80),
          visible: rect.width > 0 && rect.height > 0,
          inViewport: false,
          height: Math.round(rect.height),
          top: Math.round(rect.top),
          bottom: Math.round(rect.bottom),
          bgColor: style.backgroundColor,
          hasContent: e.innerHTML.length > 100,
          textLength: e.innerText.length,
          childElementCount: e.childElementCount
        };
      });
    });

    // Check for blank/white areas
    const blankAreas = await page.evaluate(() => {
      const allDivs = document.querySelectorAll('div, section');
      const blanks = [];
      allDivs.forEach(d => {
        const rect = d.getBoundingClientRect();
        if (rect.height > 150 && rect.width > 300 && d.children.length === 0) {
          const style = window.getComputedStyle(d);
          const bg = style.backgroundColor;
          if (bg === 'rgba(0, 0, 0, 0)' || bg === 'rgb(255, 255, 255)') {
            if (d.innerText.trim().length === 0) {
              blanks.push({
                tag: d.tagName,
                className: (d.className || '').substring(0, 60),
                height: Math.round(rect.height),
                width: Math.round(rect.width),
                top: Math.round(rect.top)
              });
            }
          }
        }
      });
      return blanks;
    });

    // Accessibility checks
    const accessibility = await page.evaluate(() => {
      const imgs = document.querySelectorAll('img');
      const imgsWithoutAlt = Array.from(imgs).filter(i => !i.hasAttribute('alt')).length;
      const links = document.querySelectorAll('a');
      const linksWithoutLabel = Array.from(links).filter(l =>
        !l.getAttribute('aria-label') && !l.getAttribute('title') && l.innerText.trim().length === 0
      ).length;
      const buttons = document.querySelectorAll('button');
      const buttonsLabelless = Array.from(buttons).filter(b =>
        !b.getAttribute('aria-label') && !b.getAttribute('title') && b.innerText.trim().length === 0
      ).length;
      const forms = document.querySelectorAll('form');
      const inputs = document.querySelectorAll('input, textarea, select');
      const inputsMissingLabel = Array.from(inputs).filter(i => {
        const id = i.id;
        if (!id) return true;
        return !document.querySelector(`label[for="${id}"]`) && !i.getAttribute('aria-label') && !i.getAttribute('placeholder');
      }).length;

      return {
        totalImages: imgs.length,
        imgsWithoutAlt,
        totalLinks: links.length,
        linksWithoutLabel,
        totalButtons: buttons.length,
        buttonsLabelless,
        totalForms: forms.length,
        totalInputs: inputs.length,
        inputsMissingLabel,
        hasViewport: !!document.querySelector('meta[name="viewport"]'),
        hasCanonical: !!document.querySelector('link[rel="canonical"]'),
        hasLang: document.documentElement.getAttribute('lang') || 'MISSING',
        hasDescription: !!document.querySelector('meta[name="description"]')
      };
    });

    // Check CTA buttons / links functionality
    const ctas = await page.evaluate(() => {
      const links = document.querySelectorAll('a[href]');
      return Array.from(links).slice(0, 20).map(l => ({
        href: l.getAttribute('href'),
        text: l.innerText.trim().substring(0, 50),
        visible: l.offsetParent !== null
      }));
    });

    // Check property cards
    const propertyCards = await page.evaluate(() => {
      const cards = document.querySelectorAll('[class*="deal"], [class*="property"], [class*="project"]');
      return Array.from(cards).slice(0, 10).map(c => ({
        className: c.className.substring(0, 60),
        text: c.innerText.substring(0, 100).replace(/\n/g, ' ')
      }));
    });

    // Check reels section
    const reelsSection = await page.evaluate(() => {
      const section = document.querySelector('#reels');
      if (!section) return { found: false };
      return {
        found: true,
        height: Math.round(section.getBoundingClientRect().height),
        textLength: section.innerText.length,
        childCount: section.childElementCount,
        hasVideoElements: section.querySelectorAll('video').length,
        hasIframes: section.querySelectorAll('iframe').length
      };
    });

    // Check forms
    const forms = await page.evaluate(() => {
      return Array.from(document.querySelectorAll('form')).map(f => ({
        id: f.id || '(no-id)',
        action: f.action,
        method: f.method,
        inputCount: f.querySelectorAll('input, textarea, select').length,
        visible: f.offsetParent !== null
      }));
    });

    // Performance metrics
    const perf = await page.evaluate(() => {
      const nav = performance.getEntriesByType('navigation')[0];
      return {
        domContentLoaded: Math.round(nav.domContentLoadedEventEnd - nav.startTime),
        loadComplete: Math.round(nav.loadEventEnd - nav.startTime),
        domInteractive: Math.round(nav.domInteractive - nav.startTime),
        responseEnd: Math.round(nav.responseEnd - nav.startTime),
        transferSize: nav.transferSize,
        encodedBodySize: nav.encodedBodySize,
        decodedBodySize: nav.decodedBodySize
      };
    });

    // Check cookie banner
    const cookieBanner = await page.evaluate(() => {
      const banner = document.querySelector('[class*="cookie"], [id*="cookie"], [class*="consent"], [id*="consent"]');
      if (!banner) return { found: false };
      const rect = banner.getBoundingClientRect();
      return {
        found: true,
        visible: rect.width > 0 && rect.height > 0,
        text: banner.innerText.substring(0, 100),
        height: Math.round(rect.height)
      };
    });

    // HTTP status codes summary
    const statusSummary = requests.reduce((acc, r) => {
      const range = Math.floor(r.status / 100) + 'xx';
      acc[range] = (acc[range] || 0) + 1;
      return acc;
    }, {});

    const result = {
      viewport: `${width}x${height}`,
      responseStatus: response?.status(),
      loadTimeMs: loadTime,
      performance: perf,
      sections: sections.length,
      sectionDetails: sections,
      blankAreas,
      accessibility,
      ctas: ctas.length,
      ctaDetails: ctas,
      propertyCards: propertyCards.length,
      propertyCardDetails: propertyCards,
      reelsSection,
      forms,
      cookieBanner,
      consoleErrors: consoleErrors.length,
      consoleErrorDetails: consoleErrors.slice(0, 10),
      consoleWarnings: consoleWarnings.length,
      networkFailures: networkFailures.length,
      networkFailureDetails: networkFailures.slice(0, 5),
      totalRequests: requests.length,
      statusSummary,
      screenshots: [
        `${viewportName}-fullpage.png`,
        `${viewportName}-viewport.png`
      ]
    };

    RESULTS.viewports[viewportName] = result;
    console.log(`[${viewportName}] DONE — ${sections.length} sections, ${consoleErrors.length} console errors, ${networkFailures.length} network failures, load: ${loadTime}ms`);

  } catch (err) {
    RESULTS.viewports[viewportName] = { error: err.message };
    console.error(`[${viewportName}] FAILED:`, err.message);
  } finally {
    await context.close();
  }
}

async function main() {
  console.log('Starting IVX Landing Page QA — End-to-End');
  console.log('Screenshots will be saved to:', SCREENSHOT_DIR);

  const browser = await chromium.launch({
    headless: true,
    args: ['--no-sandbox', '--disable-setuid-sandbox', '--disable-gpu']
  });

  try {
    // Desktop Chrome (1440x900)
    await runViewportTest(browser, 'desktop-1440', 1440, 900, 2);

    // Desktop Chrome (1920x1080)
    await runViewportTest(browser, 'desktop-1920', 1920, 1080, 1);

    // Mobile — iPhone 14 Pro (390x844)
    await runViewportTest(browser, 'mobile-iphone', 390, 844, 3);

    // Mobile — Android (360x800)
    await runViewportTest(browser, 'mobile-android', 360, 800, 3);

    // Tablet — iPad (768x1024)
    await runViewportTest(browser, 'tablet-ipad', 768, 1024, 2);

    // Build summary
    let totalErrors = 0, totalFailures = 0, totalSections = 0, allPass = true;
    for (const [name, vp] of Object.entries(RESULTS.viewports)) {
      if (vp.error) { allPass = false; continue; }
      totalErrors += vp.consoleErrors || 0;
      totalFailures += vp.networkFailures || 0;
      totalSections = vp.sections || totalSections;
      if (vp.consoleErrors > 0 || vp.networkFailures > 0) allPass = false;
    }

    RESULTS.summary = {
      allViewportsTested: Object.keys(RESULTS.viewports).length,
      totalConsoleErrors,
      totalNetworkFailures: totalFailures,
      totalSections,
      overallStatus: allPass ? 'PASS' : 'ISSUES_FOUND'
    };

    // Write results
    fs.writeFileSync('/tmp/ivx-qa-results.json', JSON.stringify(RESULTS, null, 2));
    console.log('\n=== QA RESULTS SUMMARY ===');
    console.log(JSON.stringify(RESULTS.summary, null, 2));
    console.log('\nResults saved to /tmp/ivx-qa-results.json');
    console.log('Screenshots saved to /tmp/ivx-qa-screenshots/');

  } finally {
    await browser.close();
  }
}

main().catch(err => {
  console.error('Fatal error:', err);
  process.exit(1);
});

