const { chromium } = require('playwright');
const fs = require('fs');
const path = require('path');

const SCREENSHOT_DIR = '/tmp/ivx-qa-screenshots';
fs.mkdirSync(SCREENSHOT_DIR, { recursive: true });

const RESULTS = {
  report: 'IVX Landing Page QA — End-to-End',
  timestamp: new Date().toISOString(),
  url: 'https://ivxholding.com',
  viewports: {},
  summary: {}
};

async function runTest(browser, name, width, height) {
  const context = await browser.newContext({
    viewport: { width, height },
    deviceScaleFactor: 2
  });
  const page = await context.newPage();

  const consoleErrors = [];
  const consoleWarnings = [];
  const networkFailures = [];
  const allRequests = [];

  page.on('console', msg => {
    if (msg.type() === 'error') consoleErrors.push(msg.text());
    if (msg.type() === 'warning') consoleWarnings.push(msg.text());
  });
  page.on('requestfailed', req => {
    networkFailures.push({ url: req.url(), error: req.failure()?.errorText });
  });
  page.on('response', resp => {
    allRequests.push({ url: resp.url(), status: resp.status() });
  });

  try {
    const response = await page.goto('https://ivxholding.com/', { waitUntil: 'networkidle', timeout: 45000 });
    await page.waitForTimeout(2000);

    // Screenshots
    await page.screenshot({ path: path.join(SCREENSHOT_DIR, name + '-fullpage.png'), fullPage: true });
    await page.screenshot({ path: path.join(SCREENSHOT_DIR, name + '-viewport.png'), fullPage: false });

    // Section analysis
    const sections = await page.evaluate(() => {
      return Array.from(document.querySelectorAll('section')).map(e => {
        const rect = e.getBoundingClientRect();
        const style = window.getComputedStyle(e);
        return {
          id: e.id || '(no-id)',
          visible: rect.width > 0 && rect.height > 0,
          height: Math.round(rect.height),
          top: Math.round(rect.top),
          bgColor: style.backgroundColor,
          textLength: e.innerText.length,
          childCount: e.childElementCount,
          hasImages: e.querySelectorAll('img').length,
          hasVideos: e.querySelectorAll('video').length,
          hasButtons: e.querySelectorAll('button, a[href]').length
        };
      });
    });

    // Blank areas
    const blankAreas = await page.evaluate(() => {
      const blanks = [];
      document.querySelectorAll('div, section').forEach(d => {
        const rect = d.getBoundingClientRect();
        if (rect.height > 150 && rect.width > 300 && d.children.length === 0 && d.innerText.trim().length === 0) {
          const style = window.getComputedStyle(d);
          if (style.backgroundColor === 'rgb(255, 255, 255)' || style.backgroundColor === 'rgba(0, 0, 0, 0)') {
            blanks.push({ tag: d.tagName, cls: (d.className||'').substring(0,50), h: Math.round(rect.height), top: Math.round(rect.top) });
          }
        }
      });
      return blanks;
    });

    // Accessibility
    const a11y = await page.evaluate(() => {
      const imgs = document.querySelectorAll('img');
      const imgsWithoutAlt = Array.from(imgs).filter(i => !i.hasAttribute('alt')).length;
      const links = document.querySelectorAll('a');
      const linksWithoutLabel = Array.from(links).filter(l =>
        !l.getAttribute('aria-label') && !l.getAttribute('title') && l.innerText.trim().length === 0
      ).length;
      const buttons = document.querySelectorAll('button');
      const btnsLabelless = Array.from(buttons).filter(b =>
        !b.getAttribute('aria-label') && !b.getAttribute('title') && b.innerText.trim().length === 0
      ).length;
      return {
        totalImages: imgs.length, imgsWithoutAlt,
        totalLinks: links.length, linksWithoutLabel,
        totalButtons: buttons.length, btnsLabelless,
        hasViewport: !!document.querySelector('meta[name="viewport"]'),
        hasCanonical: !!document.querySelector('link[rel="canonical"]'),
        hasLang: document.documentElement.getAttribute('lang') || 'MISSING',
        hasDescription: !!document.querySelector('meta[name="description"]'),
        hasCSP: !!document.querySelector('meta[http-equiv="Content-Security-Policy"]')
      };
    });

    // CTAs
    const ctas = await page.evaluate(() => {
      return Array.from(document.querySelectorAll('a[href]')).slice(0, 30).map(l => ({
        href: l.getAttribute('href'),
        text: l.innerText.trim().substring(0, 40),
        visible: l.offsetParent !== null
      }));
    });

    // Property cards
    const dealCards = await page.evaluate(() => {
      const cards = document.querySelectorAll('[class*="deal-card"], [class*="property-card"], [class*="project-card"]');
      return Array.from(cards).map(c => c.innerText.substring(0, 80).replace(/\n/g, ' '));
    });

    // Reels
    const reels = await page.evaluate(() => {
      const s = document.querySelector('#reels');
      if (!s) return { found: false };
      return {
        found: true,
        height: Math.round(s.getBoundingClientRect().height),
        textLen: s.innerText.length,
        children: s.childElementCount,
        videos: s.querySelectorAll('video').length,
        iframes: s.querySelectorAll('iframe').length
      };
    });

    // Forms
    const forms = await page.evaluate(() => {
      return Array.from(document.querySelectorAll('form')).map(f => ({
        id: f.id || '(no-id)',
        action: f.action,
        method: f.method,
        inputs: f.querySelectorAll('input, textarea, select').length,
        visible: f.offsetParent !== null
      }));
    });

    // Cookie banner
    const cookie = await page.evaluate(() => {
      const b = document.querySelector('[class*="cookie"], [id*="cookie"], [class*="consent"], [id*="consent"]');
      if (!b) return { found: false };
      const r = b.getBoundingClientRect();
      return { found: true, visible: r.width > 0 && r.height > 0, text: b.innerText.substring(0, 100), height: Math.round(r.height) };
    });

    // Performance
    const perf = await page.evaluate(() => {
      const nav = performance.getEntriesByType('navigation')[0];
      return {
        domContentLoaded: Math.round(nav.domContentLoadedEventEnd - nav.startTime),
        loadComplete: Math.round(nav.loadEventEnd - nav.startTime),
        domInteractive: Math.round(nav.domInteractive - nav.startTime),
        transferSize: nav.transferSize,
        encodedBodySize: nav.encodedBodySize,
        decodedBodySize: nav.decodedBodySize
      };
    });

    // Status summary
    const statusSummary = {};
    allRequests.forEach(r => {
      const range = Math.floor(r.status / 100) + 'xx';
      statusSummary[range] = (statusSummary[range] || 0) + 1;
    });

    const result = {
      viewport: width + 'x' + height,
      responseStatus: response?.status(),
      performance: perf,
      sections: sections.length,
      sectionDetails: sections,
      blankAreas,
      accessibility: a11y,
      ctas: ctas.length,
      ctaDetails: ctas,
      dealCards,
      reels,
      forms,
      cookie,
      consoleErrors: consoleErrors.length,
      consoleErrorDetails: consoleErrors.slice(0, 15),
      consoleWarnings: consoleWarnings.length,
      networkFailures: networkFailures.length,
      networkFailureDetails: networkFailures,
      totalRequests: allRequests.length,
      statusSummary
    };

    RESULTS.viewports[name] = result;
    console.log('[' + name + '] OK — ' + sections.length + ' sections, ' + consoleErrors.length + ' errors, ' + networkFailures.length + ' failed requests, load: ' + perf.loadComplete + 'ms');

  } catch (err) {
    RESULTS.viewports[name] = { error: err.message };
    console.error('[' + name + '] FAILED:', err.message);
  } finally {
    await context.close();
  }
}

async function main() {
  console.log('Starting IVX Landing Page QA...');
  const browser = await chromium.launch({ headless: true, args: ['--no-sandbox', '--disable-setuid-sandbox', '--disable-gpu'] });

  try {
    await runTest(browser, 'desktop-1440', 1440, 900);
    await runTest(browser, 'desktop-1920', 1920, 1080);
    await runTest(browser, 'mobile-iphone', 390, 844);
    await runTest(browser, 'mobile-android', 360, 800);
    await runTest(browser, 'tablet-ipad', 768, 1024);

    // Build summary
    let totalErrors = 0, totalFailures = 0, totalSections = 0;
    let allViewportsOK = true;
    for (const [name, vp] of Object.entries(RESULTS.viewports)) {
      if (vp.error) { allViewportsOK = false; continue; }
      totalErrors += vp.consoleErrors || 0;
      totalFailures += vp.networkFailures || 0;
      totalSections = vp.sections || totalSections;
    }

    RESULTS.summary = {
      totalViewports: Object.keys(RESULTS.viewports).length,
      totalConsoleErrors: totalErrors,
      totalNetworkFailures: totalFailures,
      totalSections,
      allViewportsLoaded: allViewportsOK
    };

    fs.writeFileSync('/tmp/ivx-qa-results.json', JSON.stringify(RESULTS, null, 2));
    console.log('\n=== SUMMARY ===');
    console.log(JSON.stringify(RESULTS.summary, null, 2));
    console.log('\nResults: /tmp/ivx-qa-results.json');
    console.log('Screenshots: /tmp/ivx-qa-screenshots/');

  } finally {
    await browser.close();
  }
}

main().catch(err => { console.error('Fatal:', err); process.exit(1); });
