  await page.waitForTimeout(2000);

  const failed = allResponses.filter(r => r.status >= 400);
  console.log('\\n=== FAILED REQUESTS ===');
  failed.forEach(f => console.log(f.status + ' ' + f.url));

  await browser.close();
})();
