const { chromium } = require('playwright');
const fs = require('fs');
const path = require('path');

const SCREENSHOT_DIR = '/tmp/ivx-qa-screenshots';
fs.mkdirSync(SCREENSHOT_DIR, { recursive: true });

const INTERACTIVE_RESULTS = {
  report: 'IVX Landing Page QA — Interactive Tests',
  timestamp: new Date().toISOString(),
  url: 'https://ivxholding.com',
  tests: {}
};

async function runInteractiveTests() {
  const browser = await chromium.launch({ headless: true, args: ['--no-sandbox', '--disable-setuid-sandbox', '--disable-gpu'] });
  const context = await browser.newContext({ viewport: { width: 1440, height: 900 }, deviceScaleFactor: 2 });
  const page = await context.newPage();

  const consoleErrors = [];
  page.on('console', msg => { if (msg.type() === 'error') consoleErrors.push(msg.text()); });

  console.log('=== TEST 1: Page Load ===');
  try {
    const response = await page.goto('https://ivxholding.com/', { waitUntil: 'networkidle', timeout: 45000 });
    await page.waitForTimeout(2000);
    const title = await page.title();
    INTERACTIVE_RESULTS.tests.pageLoad = {
      status: response?.status() === 200 ? 'PASS' : 'FAIL',
      statusCode: response?.status(),
      title,
      consoleErrors: consoleErrors.length
    };
    console.log('  Status: ' + response?.status() + ', Title: ' + title);
  } catch (err) {
    INTERACTIVE_RESULTS.tests.pageLoad = { status: 'FAIL', error: err.message };
    console.log('  FAILED: ' + err.message);
  }

  // Screenshot: hero
  await page.screenshot({ path: path.join(SCREENSHOT_DIR, 'interactive-01-hero.png') });

  console.log('=== TEST 2: Navigation — Scroll to Properties ===');
  try {
    await page.click('a[href="#properties"]');
    await page.waitForTimeout(1000);
    const propertiesVisible = await page.evaluate(() => {
      const el = document.querySelector('#properties');
      if (!el) return false;
      const rect = el.getBoundingClientRect();
      return rect.top < window.innerHeight && rect.bottom > 0;
    });
    await page.screenshot({ path: path.join(SCREENSHOT_DIR, 'interactive-02-properties.png') });
    INTERACTIVE_RESULTS.tests.navProperties = { status: propertiesVisible ? 'PASS' : 'FAIL', visible: propertiesVisible };
    console.log('  Properties visible: ' + propertiesVisible);
  } catch (err) {
    INTERACTIVE_RESULTS.tests.navProperties = { status: 'FAIL', error: err.message };
    console.log('  FAILED: ' + err.message);
  }

  console.log('=== TEST 3: Deal Cards Display ===');
  try {
    const deals = await page.evaluate(() => {
      const cards = document.querySelectorAll('[class*="deal-card"], [class*="property-card"], [class*="project-card"]');
      return Array.from(cards).map(c => ({
        text: c.innerText.substring(0, 120).replace(/\n/g, ' '),
        visible: c.offsetParent !== null,
        hasImage: c.querySelectorAll('img').length > 0,
        hasLink: c.querySelectorAll('a').length > 0
      }));
    });
    const allVisible = deals.length > 0 && deals.every(d => d.visible);
    INTERACTIVE_RESULTS.tests.dealCards = { status: allVisible ? 'PASS' : 'FAIL', count: deals.length, deals: deals.slice(0, 5) };
    console.log('  Deal cards: ' + deals.length + ', all visible: ' + allVisible);
  } catch (err) {
    INTERACTIVE_RESULTS.tests.dealCards = { status: 'FAIL', error: err.message };
  }

  console.log('=== TEST 4: Reels Section ===');
  try {
    await page.click('a[href="#reels"]');
    await page.waitForTimeout(1500);
    const reels = await page.evaluate(() => {
      const section = document.querySelector('#reels');
      if (!section) return { found: false };
      const videos = section.querySelectorAll('video');
      return {
        found: true,
        visible: section.offsetParent !== null,
        height: Math.round(section.getBoundingClientRect().height),
        videoCount: videos.length,
        videosLoaded: Array.from(videos).filter(v => v.readyState >= 2).length,
        videosWithPoster: Array.from(videos).filter(v => v.poster).length,
        videoPosters: Array.from(videos).map(v => v.poster ? v.poster.substring(0, 80) : null)
      };
    });
    await page.screenshot({ path: path.join(SCREENSHOT_DIR, 'interactive-04-reels.png') });
    INTERACTIVE_RESULTS.tests.reelsSection = { status: reels.found && reels.videoCount > 0 ? 'PASS' : 'PARTIAL', details: reels };
    console.log('  Reels: found=' + reels.found + ', videos=' + reels.videoCount + ', loaded=' + reels.videosLoaded);
  } catch (err) {
    INTERACTIVE_RESULTS.tests.reelsSection = { status: 'FAIL', error: err.message };
  }

  console.log('=== TEST 5: Waitlist Form Fields ===');
  try {
    const formInfo = await page.evaluate(() => {
      const form = document.querySelector('#waitlist-form');
      if (!form) return { found: false };
      form.scrollIntoView();
      const inputs = form.querySelectorAll('input, textarea, select');
      return {
        found: true,
        visible: form.offsetParent !== null,
        inputCount: inputs.length,
        fields: Array.from(inputs).map(i => ({
          name: i.name || i.id || '(unnamed)',
          type: i.type || i.tagName.toLowerCase(),
          required: i.required,
          placeholder: i.placeholder || ''
        })).slice(0, 20)
      };
    });
    await page.waitForTimeout(500);
    await page.screenshot({ path: path.join(SCREENSHOT_DIR, 'interactive-05-waitlist.png') });
    const hasRequiredFields = formInfo.fields && formInfo.fields.some(f => f.required);
    INTERACTIVE_RESULTS.tests.waitlistForm = { status: formInfo.found && formInfo.inputCount > 5 ? 'PASS' : 'FAIL', details: formInfo };
    console.log('  Form found: ' + formInfo.found + ', inputs: ' + formInfo.inputCount + ', required fields: ' + (formInfo.fields?.filter(f => f.required).length || 0));
  } catch (err) {
    INTERACTIVE_RESULTS.tests.waitlistForm = { status: 'FAIL', error: err.message };
  }

  console.log('=== TEST 6: Cookie Banner ===');
  try {
    const cookie = await page.evaluate(() => {
      const banner = document.querySelector('[class*="cookie"], [id*="cookie"], [class*="consent"], [id*="consent"]');
      if (!banner) return { found: false };
      const rect = banner.getBoundingClientRect();
      return {
        found: true,
        visible: rect.width > 0 && rect.height > 0,
        text: banner.innerText.substring(0, 200),
        height: Math.round(rect.height),
        hasAcceptButton: banner.querySelectorAll('button, a').length > 0
      };
    });
    INTERACTIVE_RESULTS.tests.cookieBanner = { status: cookie.found ? 'PASS' : 'FAIL', details: cookie };
    console.log('  Cookie banner found: ' + cookie.found + ', visible: ' + cookie.visible);
  } catch (err) {
    INTERACTIVE_RESULTS.tests.cookieBanner = { status: 'FAIL', error: err.message };
  }

  console.log('=== TEST 7: Partner Section ===');
  try {
    await page.click('a[href="#partners"]');
    await page.waitForTimeout(1000);
    const partner = await page.evaluate(() => {
      const section = document.querySelector('#partners');
      if (!section) return { found: false };
      return {
        found: true,
        visible: section.offsetParent !== null,
        height: Math.round(section.getBoundingClientRect().height),
        textLength: section.innerText.length,
        hasForm: section.querySelectorAll('form').length > 0
      };
    });
    await page.screenshot({ path: path.join(SCREENSHOT_DIR, 'interactive-07-partners.png') });
    INTERACTIVE_RESULTS.tests.partnerSection = { status: partner.found && partner.visible ? 'PASS' : 'FAIL', details: partner };
    console.log('  Partner section: found=' + partner.found + ', visible=' + partner.visible);
  } catch (err) {
    INTERACTIVE_RESULTS.tests.partnerSection = { status: 'FAIL', error: err.message };
  }

  console.log('=== TEST 8: Trust/Security Section ===');
  try {
    await page.click('a[href="#trust"]');
    await page.waitForTimeout(1000);
    const trust = await page.evaluate(() => {
      const section = document.querySelector('#trust');
      if (!section) return { found: false };
      return {
        found: true,
        visible: section.offsetParent !== null,
        height: Math.round(section.getBoundingClientRect().height),
        textLength: section.innerText.length
      };
    });
    await page.screenshot({ path: path.join(SCREENSHOT_DIR, 'interactive-08-trust.png') });
    INTERACTIVE_RESULTS.tests.trustSection = { status: trust.found && trust.visible ? 'PASS' : 'FAIL', details: trust };
    console.log('  Trust section: found=' + trust.found + ', visible=' + trust.visible);
  } catch (err) {
    INTERACTIVE_RESULTS.tests.trustSection = { status: 'FAIL', error: err.message };
  }

  console.log('=== TEST 9: How It Works Section ===');
  try {
    await page.click('a[href="#how-it-works"]');
    await page.waitForTimeout(1000);
    const hiw = await page.evaluate(() => {
      const section = document.querySelector('#how-it-works');
      if (!section) return { found: false };
      return {
        found: true,
        visible: section.offsetParent !== null,
        height: Math.round(section.getBoundingClientRect().height),
        textLength: section.innerText.length,
        stepCount: section.querySelectorAll('[class*="step"], [class*="card"]').length
      };
    });
    await page.screenshot({ path: path.join(SCREENSHOT_DIR, 'interactive-09-howitworks.png') });
    INTERACTIVE_RESULTS.tests.howItWorks = { status: hiw.found && hiw.visible ? 'PASS' : 'FAIL', details: hiw };
    console.log('  How It Works: found=' + hiw.found + ', visible=' + hiw.visible + ', steps/cards: ' + hiw.stepCount);
  } catch (err) {
    INTERACTIVE_RESULTS.tests.howItWorks = { status: 'FAIL', error: err.message };
  }

  console.log('=== TEST 10: Investor Chat Section ===');
  try {
    const chat = await page.evaluate(() => {
      const section = document.querySelector('#investor-chat');
      if (!section) return { found: false };
      section.scrollIntoView();
      return {
        found: true,
        visible: section.offsetParent !== null,
        height: Math.round(section.getBoundingClientRect().height),
        textLength: section.innerText.length,
        hasIframe: section.querySelectorAll('iframe').length > 0,
        hasForm: section.querySelectorAll('form').length > 0
      };
    });
    await page.waitForTimeout(500);
    await page.screenshot({ path: path.join(SCREENSHOT_DIR, 'interactive-10-investor-chat.png') });
    INTERACTIVE_RESULTS.tests.investorChat = { status: chat.found && chat.visible ? 'PASS' : 'FAIL', details: chat };
    console.log('  Investor Chat: found=' + chat.found + ', visible=' + chat.visible);
  } catch (err) {
    INTERACTIVE_RESULTS.tests.investorChat = { status: 'FAIL', error: err.message };
  }

  console.log('=== TEST 11: Reviews Section ===');
  try {
    const reviews = await page.evaluate(() => {
      const section = document.querySelector('#reviews');
      if (!section) return { found: false };
      section.scrollIntoView();
      return {
