const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.launch({ headless: true, args: ['--no-sandbox'] });
  const context = await browser.newContext({ viewport: { width: 390, height: 844 } });
  const page = await context.newPage();
  await page.goto('http://localhost:8765/index.html', { waitUntil: 'networkidle' });
  await page.waitForTimeout(1500);

  const check = await page.evaluate(() => {
    const body = document.body;
    const sections = document.querySelectorAll('section');
    const overflow = Array.from(sections).filter(s => s.scrollWidth > window.innerWidth + 5);
    return {
      bodyWidth: body.scrollWidth,
      windowWidth: window.innerWidth,
      overflowSections: overflow.map(s => s.id || s.className.substring(0,30))
    };
  });
  console.log('Local mobile check:', JSON.stringify(check));
  await page.screenshot({ path: '/home/user/rork-app/qa-screenshots/local-mobile-fixed.png', fullPage: true });
  await browser.close();
})();
" 2>&1

kill $SERVER_PID 2>/dev/null

