const { chromium } = require('playwright');
const fs = require('fs');

const RESULTS = {
  report: 'IVX Landing Page — Form QA',
  timestamp: new Date().toISOString(),
  url: 'https://ivxholding.com',
  tests: {}
};

async function testFormSubmission() {
  const browser = await chromium.launch({ headless: true, args: ['--no-sandbox', '--disable-setuid-sandbox'] });
  const context = await browser.newContext({ viewport: { width: 1440, height: 900 }, deviceScaleFactor: 2 });
  const page = await context.newPage();

  const consoleErrors = [];
  const networkRequests = [];
  page.on('console', msg => { if (msg.type() === 'error') consoleErrors.push(msg.text()); });
  page.on('request', req => { networkRequests.push({ url: req.url(), method: req.method() }); });

  try {
    console.log('=== Loading page and navigating to waitlist form ===');
    await page.goto('https://ivxholding.com/', { waitUntil: 'networkidle', timeout: 45000 });
    await page.waitForTimeout(1500);

    // Click the main CTA to scroll to waitlist
    await page.click('a[href="#waitlist"]');
    await page.waitForTimeout(800);

    // Fill waitlist form fields
    const testEmail = 'qa-browser-' + Date.now() + '@ivxtest.local';
    const testPhone = '305555' + (1000 + Math.floor(Math.random() * 8999));

    await page.fill('#waitlist-first-name', 'QA');
    await page.fill('#waitlist-last-name', 'Browser');
    await page.fill('#waitlist-email', testEmail);
    await page.fill('#waitlist-phone', testPhone);

    // Select investor role if available
    const roleSelect = await page.$('#waitlist-role');
    if (roleSelect) await roleSelect.selectOption('investor');

    // Check consent/ToS if available
    const consentCheckbox = await page.$('#waitlist-consent');
    if (consentCheckbox) await consentCheckbox.check();

    const tosCheckbox = await page.$('#waitlist-tos');
    if (tosCheckbox) await tosCheckbox.check();

    // Submit the form
    await page.click('#waitlist-submit-btn');
    await page.waitForTimeout(3000);

    // Check for success/error messages
    const pageContent = await page.evaluate(() => {
      const body = document.body.innerText;
      return {
        hasSuccess: /success|submitted|thank you|confirmed|verified/i.test(body),
        hasError: /error|failed|invalid|required/i.test(body),
        relevantText: body.substring(0, 2000)
      };
    });

    await page.screenshot({ path: '/home/user/rork-app/qa-screenshots/form-submit-result.png' });

    RESULTS.tests.waitlistForm = {
      status: pageContent.hasSuccess && !pageContent.hasError ? 'PASS' : 'NEEDS_REVIEW',
      email: testEmail,
      phone: testPhone,
      hasSuccess: pageContent.hasSuccess,
      hasError: pageContent.hasError,
      consoleErrors: consoleErrors.length,
      networkCalls: networkRequests.filter(r => r.url.includes('api') || r.url.includes('trpc')).map(r => r.url).slice(0, 10)
    };

    console.log('Waitlist form test:', JSON.stringify(RESULTS.tests.waitlistForm, null, 2));

  } catch (err) {
    RESULTS.tests.waitlistForm = { status: 'FAIL', error: err.message };
    console.log('Waitlist form failed:', err.message);
  } finally {
    await context.close();
  }
}

async function testMemberRegistration() {
  const browser = await chromium.launch({ headless: true, args: ['--no-sandbox', '--disable-setuid-sandbox'] });
  const context = await browser.newContext({ viewport: { width: 1440, height: 900 }, deviceScaleFactor: 2 });
  const page = await context.newPage();

  const consoleErrors = [];
  page.on('console', msg => { if (msg.type() === 'error') consoleErrors.push(msg.text()); });

  try {
    console.log('=== Testing member registration modal ===');
    await page.goto('https://ivxholding.com/', { waitUntil: 'networkidle', timeout: 45000 });
    await page.waitForTimeout(1500);

    // Try to open member registration (could be a button or link)
    const regButton = await page.$('#open-member-reg, .open-member-reg, a[href="#register"]');
    if (regButton) {
      await regButton.click();
      await page.waitForTimeout(1000);
    } else {
      // Try clicking any "Get Started" or "Create Account" button
      const buttons = await page.$$('a, button');
      for (const btn of buttons) {
        const text = await btn.textContent();
        if (text && /get started|create account|join|sign up|register/i.test(text)) {
          await btn.click();
          await page.waitForTimeout(1000);
          break;
        }
      }
    }

    await page.screenshot({ path: '/home/user/rork-app/qa-screenshots/member-reg-attempt.png' });

    const formInfo = await page.evaluate(() => {
      const form = document.querySelector('#mreg-form');
      if (!form) return { found: false };
      const inputs = form.querySelectorAll('input, select');
      return {
        found: true,
        visible: form.offsetParent !== null,
        inputCount: inputs.length,
        fields: Array.from(inputs).map(i => ({
          name: i.name || i.id || '(unnamed)',
          type: i.type || i.tagName.toLowerCase(),
          required: i.required
        })).slice(0, 20)
      };
    });

    RESULTS.tests.memberRegistration = {
      status: formInfo.found ? 'PASS' : 'NOT_FOUND',
      formInfo
    };

    console.log('Member registration test:', JSON.stringify(RESULTS.tests.memberRegistration, null, 2));

  } catch (err) {
    RESULTS.tests.memberRegistration = { status: 'FAIL', error: err.message };
    console.log('Member registration failed:', err.message);
  } finally {
    await context.close();
  }
}

async function main() {
  await testFormSubmission();
  await testMemberRegistration();

  fs.writeFileSync('/tmp/ivx-form-qa-results.json', JSON.stringify(RESULTS, null, 2));
  console.log('\n=== FORM QA SUMMARY ===');
  console.log(JSON.stringify(RESULTS.tests, null, 2));
}

main().catch(err => { console.error('Fatal:', err); process.exit(1); });

